# Math utilities module

def square(x: float) -> float:
    return x * x

def factorial(n: int) -> int:
    result: int = 1
    i: int = 2
    while i <= n:
        result = result * i
        i = i + 1
    return result

def sum_of_squares(values: list[float]) -> float:
    total: float = 0.0
    for v in values:
        total = total + square(v)
    return total
